insert into forecast_vintages (source_id,vintage_label,published_date,horizon_end_year,source_url,archive_url,notes) values ('eia-annual-energy-outlook-aeo','AEO2023','2023-03-16',2050,'https://www.eia.gov/outlooks/aeo/','https://www.eia.gov/outlooks/aeo/archive.php','EIA Annual Energy Outlook 2023 (released 2023-03-16). Vintage row seeded for lineage; per-year electricity totals across cases require the EIA API / AEO Table Browser (Myke gate: EIA_API_KEY) and were not machine-extractable here (see PR report).') on conflict (source_id,vintage_label) do update set published_date=excluded.published_date, horizon_end_year=excluded.horizon_end_year, source_url=excluded.source_url, archive_url=excluded.archive_url, notes=excluded.notes;
insert into forecast_vintages (source_id,vintage_label,published_date,horizon_end_year,source_url,archive_url,notes) values ('eia-annual-energy-outlook-aeo','AEO2025','2025-04-15',2050,'https://www.eia.gov/outlooks/aeo/','https://www.eia.gov/outlooks/aeo/archive.php','EIA Annual Energy Outlook 2025 (released April 2025; exact day approximate). Reference + alternative cases to 2050.') on conflict (source_id,vintage_label) do update set published_date=excluded.published_date, horizon_end_year=excluded.horizon_end_year, source_url=excluded.source_url, archive_url=excluded.archive_url, notes=excluded.notes;
insert into forecast_observations (vintage_id,source_id,jurisdiction_id,attribute_code,target_year,metric_name,value,unit,scenario,confidence,method,notes) values ((select vintage_id from forecast_vintages where source_id='eia-annual-energy-outlook-aeo' and vintage_label='AEO2025'),'eia-annual-energy-outlook-aeo',null,'PWR-07',2050,'Total U.S. electricity consumption',6646.17,'TWh','reference','medium','manual','AEO2025 Reference case: total U.S. electricity consumption ~= 6,646.17 TWh by 2050. Source: RBAC review of EIA AEO2025 (citing the AEO2025 data browser). Corroborated by EIA AEO2025 (~50% rise to ~6,000 TWh generation by 2050).');
